#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

void** allocate_2d_matrix(size_t rows, size_t cols, size_t element_size) {
    if (rows == 0 || cols == 0 || element_size == 0) {
        return NULL;
    }
    
    // Check for potential overflow
    if (rows > SIZE_MAX / cols / element_size) {
        return NULL;
    }
    
    size_t total_size = rows * cols * element_size;
    
    // Allocate array of pointers
    void** matrix = (void**)malloc(rows * sizeof(void*));
    if (matrix == NULL) {
        return NULL;
    }
    
    // Allocate memory for each row
    for (size_t i = 0; i < rows; i++) {
        matrix[i] = malloc(cols * element_size);
        if (matrix[i] == NULL) {
            // Free previously allocated memory
            for (size_t j = 0; j < i; j++) {
                free(matrix[j]);
            }
            free(matrix);
            return NULL;
        }
    }
    
    return matrix;
}

void free_2d_matrix(void** matrix, size_t rows) {
    if (matrix == NULL) {
        return;
    }
    
    for (size_t i = 0; i < rows; i++) {
        free(matrix[i]);
    }
    free(matrix);
}

int main() {
    size_t rows, cols;
    printf("Enter number of rows: ");
    scanf("%zu", &rows);
    printf("Enter number of columns: ");
    scanf("%zu", &cols);
    
    // Allocate 2D matrix of doubles
    void** matrix = allocate_2d_matrix(rows, cols, sizeof(double));
    
    if (matrix == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }
    
    // Initialize matrix elements
    for (size_t i = 0; i < rows; i++) {
        double* row = (double*)matrix[i];
        for (size_t j = 0; j < cols; j++) {
            row[j] = 0.0;
        }
    }
    
    // Use matrix here...
    
    // Free allocated memory
    free_2d_matrix(matrix, rows);
    
    return 0;
}